const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const env = typeof $env !== 'undefined' ? $env : {};

function header(name) {
  const wanted = name.toLowerCase();
  for (const [key, value] of Object.entries(headers)) {
    if (key.toLowerCase() === wanted) return value;
  }
  return undefined;
}

const expectedSecret = env.DAGENT_SHORTCUT_SECRET || '';
const providedSecret = header('x-dagent-shortcut-secret') || '';
if (!expectedSecret || providedSecret !== expectedSecret) {
  throw new Error('invalid shortcut secret');
}

const task = body.task || body.text || body.idea;
if (!task || !String(task).trim()) {
  throw new Error('task is required');
}

const idempotencyKey = body.idempotency_key || `n8n-${$execution.id}`;
const payload = {
  intent: body.intent || 'capture_idea',
  task: String(task),
  source: body.source || 'apple_watch',
  input_type: body.input_type || 'voice',
  idempotency_key: idempotencyKey,
};

for (const key of ['repo', 'tool', 'files', 'priority', 'require_approval', 'dry_run', 'metadata']) {
  if (body[key] !== undefined && body[key] !== null && body[key] !== '') {
    payload[key] = body[key];
  }
}

return [{ json: { payload, idempotency_key: idempotencyKey } }];
